// MARK: - Secure Password Storage Utility for iOS 10+

/// Errors that can occur during password operations
enum PasswordStorageError: Error, LocalizedError {
    case hashingFailed
    case keychainSaveFailed(OSStatus)
    case keychainReadFailed(OSStatus)
    case keychainDeleteFailed(OSStatus)
    case invalidData
    case saltGenerationFailed
    case passwordMismatch
    
    var errorDescription: String? {
        switch self {
        case .hashingFailed:
            return "Failed to hash the password."
        case .keychainSaveFailed(let status):
            return "Failed to save to Keychain. Status: \(status)"
        case .keychainReadFailed(let status):
            return "Failed to read from Keychain. Status: \(status)"
        case .keychainDeleteFailed(let status):
            return "Failed to delete from Keychain. Status: \(status)"
        case .invalidData:
            return "Invalid data retrieved from storage."
        case .saltGenerationFailed:
            return "Failed to generate cryptographically secure salt."
        case .passwordMismatch:
            return "Password does not match."
        }
    }
}

/// Represents a stored password hash with its associated salt and parameters
struct PasswordRecord: Codable {
    let salt: Data
    let hash: Data
    let iterations: UInt32
    let keyLength: Int
    let algorithm: String
    
    /// Serialize to Data for Keychain storage
    func serialize() throws -> Data {
        return try JSONEncoder().encode(self)
    }
    
    /// Deserialize from Data
    static func deserialize(from data: Data) throws -> PasswordRecord {
        return try JSONDecoder().decode(PasswordRecord.self, from: data)
    }
}

/// Secure password hashing using PBKDF2 with CommonCrypto (available iOS 2+)
final class PasswordHasher {
    
    /// Salt length in bytes (32 bytes = 256 bits)
    static let saltLength = 32
    
    /// Derived key length in bytes (32 bytes = 256 bits)
    static let keyLength = 32
    
    /// Number of PBKDF2 iterations - high enough for security, tuned for mobile
    /// OWASP recommends 600,000 for PBKDF2-SHA256 as of 2023
    static let iterations: UInt32 = 600_000
    
    /// Algorithm identifier for record keeping
    static let algorithmIdentifier = "PBKDF2-HMAC-SHA256"
    
    // MARK: - Cryptographically Secure Random Salt Generation
    
    /// Generate a cryptographically secure random salt using Security framework
    static func generateSalt(length: Int = saltLength) throws -> Data {
        var saltBytes = [UInt8](repeating: 0, count: length)
        let status = SecRandomCopyBytes(kSecRandomDefault, length, &saltBytes)
        
        guard status == errSecSuccess else {
            throw PasswordStorageError.saltGenerationFailed
        }
        
        return Data(saltBytes)
    }
    
    // MARK: - PBKDF2 Hashing
    
    /// Hash a password using PBKDF2-HMAC-SHA256
    /// - Parameters:
    ///   - password: The plaintext password to hash
    ///   - salt: The cryptographic salt
    ///   - iterations: Number of PBKDF2 iterations
    ///   - keyLength: Desired derived key length in bytes
    /// - Returns: The derived key as Data
    static func hashPassword(
        _ password: String,
        salt: Data,
        iterations: UInt32 = iterations,
        keyLength: Int = keyLength
    ) throws -> Data {
        
        guard let passwordData = password.data(using: .utf8) else {
            throw PasswordStorageError.hashingFailed
        }
        
        var derivedKey = [UInt8](repeating: 0, count: keyLength)
        
        let status = salt.withUnsafeBytes { saltBuffer -> Int32 in
            guard let saltPointer = saltBuffer.baseAddress?.assumingMemoryBound(to: UInt8.self) else {
                return -1
            }
            
            return passwordData.withUnsafeBytes { passwordBuffer -> Int32 in
                guard let passwordPointer = passwordBuffer.baseAddress?.assumingMemoryBound(to: Int8.self) else {
                    return -1
                }
                
                return CCKeyDerivationPBKDF(
                    CCPBKDFAlgorithm(kCCPBKDF2),
                    passwordPointer,
                    passwordData.count,
                    saltPointer,
                    salt.count,
                    CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA256),
                    iterations,
                    &derivedKey,
                    keyLength
                )
            }
        }
        
        guard status == kCCSuccess else {
            throw PasswordStorageError.hashingFailed
        }
        
        return Data(derivedKey)
    }
    
    /// Create a complete password record with fresh salt
    static func createPasswordRecord(for password: String) throws -> PasswordRecord {
        let salt = try generateSalt()
        let hash = try hashPassword(password, salt: salt)
        
        return PasswordRecord(
            salt: salt,
            hash: hash,
            iterations: iterations,
            keyLength: keyLength,
            algorithm: algorithmIdentifier
        )
    }
    
    /// Verify a password against a stored record using constant-time comparison
    static func verifyPassword(_ password: String, against record: PasswordRecord) throws -> Bool {
        let candidateHash = try hashPassword(
            password,
            salt: record.salt,
            iterations: record.iterations,
            keyLength: record.keyLength
        )
        
        return constantTimeCompare(candidateHash, record.hash)
    }
    
    // MARK: - Constant-Time Comparison
    
    /// Compare two Data values in constant time to prevent timing attacks
    static func constantTimeCompare(_ a: Data, _ b: Data) -> Bool {
        guard a.count == b.count else {
            return false
        }
        
        var result: UInt8 = 0
        
        for i in 0..<a.count {
            result |= a[a.startIndex + i] ^ b[b.startIndex + i]
        }
        
        return result == 0
    }
}

// MARK: - Keychain Storage Manager

/// Manages secure storage of password records in the iOS Keychain
final class KeychainPasswordStore {
    
    /// Service identifier for Keychain items
    private let service: String
    
    /// Access group for shared Keychain access (optional)
    private let accessGroup: String?
    
    init(service: String = "com.app.passwordstore", accessGroup: String? = nil) {
        self.service = service
        self.accessGroup = accessGroup
    }
    
    // MARK: - Save Password Record
    
    /// Save a password record to the Keychain for a given account
    /// - Parameters:
    ///   - record: The password record to store
    ///   - account: The account identifier (e.g., username)
    func savePasswordRecord(_ record: PasswordRecord, forAccount account: String) throws {
        let data = try record.serialize()
        
        // First try to delete any existing item
        try? deletePasswordRecord(forAccount: account)
        
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            kSecAttrDescription as String: "Offline authentication password hash"
        ]
        
        if let accessGroup = accessGroup {
            query[kSecAttrAccessGroup as String] = accessGroup
        }
        
        let status = SecItemAdd(query as CFDictionary, nil)
        
        guard status == errSecSuccess else {
            throw PasswordStorageError.keychainSaveFailed(status)
        }
    }
    
    // MARK: - Retrieve Password Record
    
    /// Retrieve a password record from the Keychain for a given account
    /// - Parameter account: The account identifier
    /// - Returns: The stored password record, or nil if not found
    func retrievePasswordRecord(forAccount account: String) throws -> PasswordRecord? {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        if let accessGroup = accessGroup {
            query[kSecAttrAccessGroup as String] = accessGroup
        }
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        switch status {
        case errSecSuccess:
            guard let data = result as? Data else {
                throw PasswordStorageError.invalidData
            }
            return try PasswordRecord.deserialize(from: data)
            
        case errSecItemNotFound:
            return nil
            
        default:
            throw PasswordStorageError.keychainReadFailed(status)
        }
    }
    
    // MARK: - Delete Password Record
    
    /// Delete a password record from the Keychain
    /// - Parameter account: The account identifier
    func deletePasswordRecord(forAccount account: String) throws {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        
        if let accessGroup = accessGroup {
            query[kSecAttrAccessGroup as String] = accessGroup
        }
        
        let status = SecItemDelete(query as CFDictionary)
        
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw PasswordStorageError.keychainDeleteFailed(status)
        }
    }
    
    // MARK: - Check if Account Exists
    
    /// Check if a password record exists for a given account
    func hasPasswordRecord(forAccount account: String) -> Bool {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecReturnData as String: false
        ]
        
        if let accessGroup = accessGroup {
            query[kSecAttrAccessGroup as String] = accessGroup
        }
        
        let status = SecItemCopyMatching(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    // MARK: - List All Accounts
    
    /// List all account identifiers that have stored password records
    func listAccounts() throws -> [String] {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecReturnAttributes as String: true,
            kSecMatchLimit as String: kSecMatchLimitAll
        ]
        
        if let accessGroup = accessGroup {
            query[kSecAttrAccessGroup as String] = accessGroup
        }
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        switch status {
        case errSecSuccess:
            guard let items = result as? [[String: Any]] else {
                return []
            }
            return items.compactMap { $0[kSecAttrAccount as String] as? String }
            
        case errSecItemNotFound:
            return []
            
        default:
            throw PasswordStorageError.keychainReadFailed(status)
        }
    }
    
    // MARK: - Delete All Records
    
    /// Delete all password records for this service
    func deleteAllRecords() throws {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service
        ]
        
        if let accessGroup = accessGroup {
            query[kSecAttrAccessGroup as String] = accessGroup
        }
        
        let status = SecItemDelete(query as CFDictionary)
        
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw PasswordStorageError.keychainDeleteFailed(status)
        }
    }
}

// MARK: - High-Level Authentication Manager

/// Provides a simple interface for password registration and offline verification
final class OfflineAuthenticationManager {
    
    private let store: KeychainPasswordStore
    
    /// Maximum number of failed authentication attempts before lockout
    private let maxFailedAttempts: Int
    
    /// Lockout duration in seconds
    private let lockoutDuration: TimeInterval
    
    /// UserDefaults key prefix for tracking failed attempts
    private let failedAttemptsKeyPrefix = "com.app.auth.failedAttempts."
    private let lockoutTimestampKeyPrefix = "com.app.auth.lockoutTimestamp."
    
    init(
        service: String = "com.app.passwordstore",
        accessGroup: String? = nil,
        maxFailedAttempts: Int = 5,
        lockoutDuration: TimeInterval = 300 // 5 minutes
    ) {
        self.store = KeychainPasswordStore(service: service, accessGroup: accessGroup)
        self.maxFailedAttempts = maxFailedAttempts
        self.lockoutDuration = lockoutDuration
    }
    
    // MARK: - Registration
    
    /// Register a new password for an account
    /// - Parameters:
    ///   - password: The plaintext password
    ///   - account: The account identifier
    func registerPassword(_ password: String, forAccount account: String) throws {
        // Validate password strength
        try validatePasswordStrength(password)
        
        // Create and store the password record
        let record = try PasswordHasher.createPasswordRecord(for: password)
        try store.savePasswordRecord(record, forAccount: account)
        
        // Reset any failed attempt counters
        resetFailedAttempts(forAccount: account)
    }
    
    // MARK: - Authentication
    
    /// Authenticate a user with their password (works offline)
    /// - Parameters:
    ///   - password: The plaintext password to verify
    ///   - account: The account identifier
    /// - Returns: true if authentication succeeds
    @discardableResult
    func authenticate(password: String, forAccount account: String) throws -> Bool {
        // Check for lockout
        if isLockedOut(account: account) {
            let remainingTime = lockoutRemainingTime(forAccount: account)
            print("Account is locked out. Try again in \(Int(remainingTime)) seconds.")
            return false
        }
        
        // Retrieve stored record
        guard let record = try store.retrievePasswordRecord(forAccount: account) else {
            // Perform a dummy hash to prevent timing-based account enumeration
            let dummySalt = try PasswordHasher.generateSalt()
            _ = try? PasswordHasher.hashPassword(password, salt: dummySalt)
            return false
        }
        
        // Verify the password
        let isValid = try PasswordHasher.verifyPassword(password, against: record)
        
        if isValid {
            resetFailedAttempts(forAccount: account)
            return true
        } else {
            incrementFailedAttempts(forAccount: account)
            return false
        }
    }
    
    // MARK: - Password Update
    
    /// Update the password for an account (requires old password verification)
    func updatePassword(
        oldPassword: String,
        newPassword: String,
        forAccount account: String
    ) throws {
        // Verify old password first
        let isAuthenticated = try authenticate(password: oldPassword, forAccount: account)
        
        guard isAuthenticated else {
            throw PasswordStorageError.passwordMismatch
        }
        
        // Validate and store new password
        try validatePasswordStrength(newPassword)
        let record = try PasswordHasher.createPasswordRecord(for: newPassword)
        try store.savePasswordRecord(record, forAccount: account)
    }
    
    // MARK: - Account Management
    
    /// Check if an account has a registered password
    func isAccountRegistered(_ account: String) -> Bool {
        return store.hasPasswordRecord(forAccount: account)
    }
    
    /// Delete an account's password record
    func deleteAccount(_ account: String) throws {
        try store.deletePasswordRecord(forAccount: account)
        resetFailedAttempts(forAccount: account)
    }
    
    /// List all registered accounts
    func listRegisteredAccounts() throws -> [String] {
        return try store.listAccounts()
    }
    
    // MARK: - Password Strength Validation
    
    /// Validate that a password meets minimum security requirements
    private func validatePasswordStrength(_ password: String) throws {
        guard password.count >= 8 else {
            throw PasswordValidationError.tooShort(minimumLength: 8)
        }
        
        guard password.count <= 128 else {
            throw PasswordValidationError.tooLong(maximumLength: 128)
        }
        
        let hasUppercase = password.rangeOfCharacter(from: .uppercaseLetters) != nil
        let hasLowercase = password.rangeOfCharacter(from: .lowercaseLetters) != nil
        let hasDigit = password.rangeOfCharacter(from: .decimalDigits) != nil
        let hasSpecial = password.rangeOfCharacter(from: CharacterSet.alphanumerics.inverted) != nil
        
        var complexityScore = 0
        if hasUppercase { complexityScore += 1 }
        if hasLowercase { complexityScore += 1 }
        if hasDigit { complexityScore += 1 }
        if hasSpecial { complexityScore += 1 }
        
        guard complexityScore >= 3 else {
            throw PasswordValidationError.insufficientComplexity
        }
    }
    
    // MARK: - Brute Force Protection
    
    private func failedAttemptsKey(forAccount account: String) -> String {
        return failedAttemptsKeyPrefix + account
    }
    
    private func lockoutTimestampKey(forAccount account: String) -> String {
        return lockoutTimestampKeyPrefix + account
    }
    
    private func getFailedAttempts(forAccount account: String) -> Int {
        return UserDefaults.standard.integer(forKey: failedAttemptsKey(forAccount: account))
    }
    
    private func incrementFailedAttempts(forAccount account: String) {
        let current = getFailedAttempts(forAccount: account) + 1
        UserDefaults.standard.set(current, forKey: failedAttemptsKey(forAccount: account))
        
        if current >= maxFailedAttempts {
            UserDefaults.standard.set(
                Date().timeIntervalSince1970,
                forKey: lockoutTimestampKey(forAccount: account)
            )
        }
    }
    
    private func resetFailedAttempts(forAccount account: String) {
        UserDefaults.standard.removeObject(forKey: failedAttemptsKey(forAccount: account))
        UserDefaults.standard.removeObject(forKey: lockoutTimestampKey(forAccount: account))
    }
    
    private func isLockedOut(account: String) -> Bool {
        let failedAttempts = getFailedAttempts(forAccount: account)
        guard failedAttempts >= maxFailedAttempts else { return false }
        
        let lockoutTimestamp = UserDefaults.standard.double(forKey: lockoutTimestampKey(forAccount: account))
        guard lockoutTimestamp > 0 else { return false }
        
        let elapsed = Date().timeIntervalSince1970 - lockoutTimestamp
        
        if elapsed >= lockoutDuration {
            resetFailedAttempts(forAccount: account)
            return false
        }
        
        return true
    }
    
    func lockoutRemainingTime(forAccount account: String) -> TimeInterval {
        let lockoutTimestamp = UserDefaults.standard.double(forKey: lockoutTimestampKey(forAccount: account))
        guard lockoutTimestamp > 0 else { return 0 }
        
        let elapsed = Date().timeIntervalSince1970 - lockoutTimestamp
        return max(0, lockoutDuration - elapsed)
    }
}

// MARK: - Password Validation Errors

enum PasswordValidationError: Error, LocalizedError {
    case tooShort(minimumLength: Int)
    case tooLong(maximumLength: Int)
    case insufficientComplexity
    
    var errorDescription: String? {
        switch self {
        case .tooShort(let min):
            return "Password must be at least \(min) characters long."
        case .tooLong(let max):
            return "Password must not exceed \(max) characters."
        case .insufficientComplexity:
            return "Password must contain at least 3 of: uppercase, lowercase, digits, special characters."
        }
    }
}

// MARK: - Usage Example

func demonstrateUsage() {
    let authManager = OfflineAuthenticationManager(
        service: "com.myapp.auth",
        maxFailedAttempts: 5,
        lockoutDuration: 300
    )
    
    let username = "john.doe"
    let password = "MySecure!Pass123"
    
    // Register a new user
    do {
        try authManager.registerPassword(password, forAccount: username)
        print("✅ Password registered successfully for \(username)")
    } catch {
        print("❌ Registration failed: \(error.localizedDescription)")
        return
    }
    
    // Authenticate offline
    do {
        let isAuthenticated = try authManager.authenticate(
            password: password,
            forAccount: username
        )
        print(isAuthenticated ? "✅ Authentication successful" : "❌ Authentication failed")
    } catch {
        print("❌ Authentication error: \(error.localizedDescription)")
    }
    
    // Test wrong password
    do {
        let isAuthenticated = try authManager.authenticate(
            password: "WrongPassword!1",
            forAccount: username
        )
        print(isAuthenticated ? "✅ Authentication successful" : "❌ Wrong password rejected correctly")
    } catch {
        print("❌ Authentication error: \(error.localizedDescription)")
    }
    
    // Update password
    do {
        let newPassword = "NewSecure!Pass456"
        try authManager.updatePassword(
            oldPassword: password,
            newPassword: newPassword,
            forAccount: username
        )
        print("✅ Password updated successfully")
        
        // Verify new password works
        let isAuthenticated = try authManager.authenticate(
            password: newPassword,
            forAccount: username
        )
        print(isAuthenticated ? "✅ New password works" : "❌ New password failed")
    } catch {
        print("❌ Password update error: \(error.localizedDescription)")
    }
    
    // List accounts
    do {
        let accounts = try authManager.listRegisteredAccounts()
        print("📋 Registered accounts: \(accounts)")
    } catch {
        print("❌ Error listing accounts: \(error.localizedDescription)")
    }
}